const path = require("path");
const fs = require("fs");

const problemsFile = path.resolve(__dirname, "../../data/problems.json");

function loadProblems() {
  const raw = fs.readFileSync(problemsFile, "utf8");
  return JSON.parse(raw);
}

/**
 * Get detailed problem info by problemId including component statistics.
 * @param {string} problemId
 * @returns {object} problem detail with component statistics
 * @throws {Error} if problem not found
 */
function getProblemDetail(problemId) {
  const problems = loadProblems();
  const problem = problems.find(p => p.id === problemId);
  if (!problem) {
    const err = new Error(`Problem with id ${problemId} not found`);
    err.status = 404;
    throw err;
  }

  // Aggregate component statistics
  // languageCounts: { [language]: count }
  // statusCounts: { [status]: count }
  // maxPoints: maximum points among components

  const languageCounts = {};
  const statusCounts = {};
  let maxPoints = 0;

  if (Array.isArray(problem.components)) {
    for (const comp of problem.components) {
      if (comp.language) {
        languageCounts[comp.language] = (languageCounts[comp.language] || 0) + 1;
      }
      if (comp.status) {
        statusCounts[comp.status] = (statusCounts[comp.status] || 0) + 1;
      }
      if (typeof comp.points === "number" && comp.points > maxPoints) {
        maxPoints = comp.points;
      }
    }
  }

  return {
    ...problem,
    componentStats: {
      languageCounts,
      statusCounts,
      maxPoints
    }
  };
}

module.exports = {
  getProblemDetail
};
