  const problemId = req.params.problemId;
  try {
    const detail = ProblemsService.getProblemDetail(problemId);
    res.json(detail);
  } catch (err) {
    if (err.status === 404) {
      res.status(404).json({ error: `Problem with id ${problemId} not found` });
    } else {
      res.status(500).json({ error: "Internal server error" });
    }
  }
}

